<template>
    <div class="burger" 
        v-on:click="burgerAnim" 
        :class="{cross: showMenu}">
        <span></span>
        <span></span>
        <span></span>
    </div>
</template>
<script>
export default {
    data: () => ({
        showMenu: false 
    }),
    methods: {
        burgerAnim(){
            this.showMenu = !this.showMenu;
            this.$emit('menuVisibility', this.showMenu); //передать информацию открыто меню или нет в header
        }
    },
    created(){
        let that = this;
        document.addEventListener('click', function (e) {
            let menu = document.querySelector(".main-menu-content");
            let cross = document.querySelector(".burger");
            if(cross != null){
                menu.addEventListener('click', function(event) {
                    event.stopPropagation();
                });
                if(that.showMenu && e.target != menu &&  e.target != cross){
                    that.showMenu = false
                }
            }
        });
    }
}
</script>

