<template>
    <div>
        <div class="order-items" v-if="countItems">
            <orderBasketItem 
            v-for="(element, index) in items" 
            v-bind:key="element.id" 
            v-bind:number="index" 
            v-bind:productId="element.id" 
            v-bind:title="element.title" 
            v-bind:status="status" 
            v-on:remove="removeFromList(element.id)">
            </orderBasketItem>
        </div>
        <div class="order-items" v-if="!countItems">
            Товаров в корзине нет!
        </div>
    </div>
</template>
<script>
import OrderBasketItem from "@/components/order/basketItem";
export default {
    name: 'orderList',
    components: {
        OrderBasketItem
    },
    data: function(){
        return {
            items: [],
            collectionId: 0
        }
    },
    props: [
        "status"
    ],
    methods: {
        removeFromList(id) {
            this.items = this.items.filter(item => item.id !== id)
        },
        getProducts(){
            let basketItems = this.$store.state.basketItems;
            let tmp = [];

            for(let i = 0; i < basketItems.length; i++){
                let item = basketItems[i];
                
                // проверяем актуальность, чтобы избежать дублей
                let isActial = true;
                for(let k = 0; k < tmp.length; k++){
                    if(tmp[k] == item.productId){
                        isActial = false;
                    }
                }

                if(isActial){
                    this.items.push({
                        id: item.productId,
                        title: item.productName,
                        picture: ''
                    });

                    tmp.push(item.productId);
                }
            }
        }
    },
    watch: {
        status: function(newValue, oldValue){
            if(this.$store.state.basketItems.length == 0){
                this.items = [];
            }
        }
    },
    computed: {
        countItems: function () {
			return Object.keys(this.items).length;
		},
    },
    created() {
        
    },
    mounted(){
        this.getProducts();
    }
}
</script>