<template>
    <header>
        <div class="container header-container">
            <div v-on:click="back" class="back-button"></div>
            <Burger
                 v-on:menuVisibility="menuVisibility"
                 v-on:click="showMenu = !showMenu"
            ></Burger>
            <User></User>
            <Menu
                 v-bind:showMenu="showMenu"
                 v-on:hideMenu="hideMenu"
            ></Menu>
            
        </div>
        <component :is="SubHeader" data-user="Ivan"></component>
    </header>
</template>
<script>
import Burger from "@/components/header/header-components/Burger"
import Menu from "@/components/header/header-components/Menu"
import User from "@/components/header/header-components/User"
import SubHeader from "@/components/header/header-components/subHeader"
export default {
    data: () => ({
        showMenu: false
    }),
    components: {
        Burger, Menu, User, SubHeader
    },
    methods: {
        menuVisibility(data){
            this.showMenu = data;
        },
        hideMenu(data){
            this.showMenu = data;
        },
        back(){
            this.$router.go(-1)
        }
    },
    computed: {
        SubHeader(){
            return this.$route.meta.subHeader
        }
    },
     created(){
        let that = this;
        document.addEventListener('click', function (e) {
            let menu = document.querySelector(".main-menu-content");
            let cross = document.querySelector(".burger");
            if(cross != null){
                menu.addEventListener('click', function(event) {
                    event.stopPropagation();
                });
                
                if(that.showMenu && e.target != menu &&  e.target != cross){
                    that.showMenu = false
                }
            }
        });
    }
    
}
</script>