<template>
    <div class="order-item" :class="{showImg: showFullImg}">
        <div class="front">
            <span class="order-item__num">{{number+1}}</span>
            <!--<a href="" class="order-item__edit-btn"></a>-->
            <button class="order-item__del-btn" v-on:click.prevent="onRemove(id)"></button>
            <div class="order-item__img-block" v-on:click="showFullImg = true">
                <img :src="picture" :alt="title" v-if="picture">
            </div>
            <div class="order-item__discription-block">
                <h4 class="order-item__title">{{title}}</h4>
                <!-- <div class="order-item__color" v-if="countOffers">
                    <div class="order-item__table-header">
                        <p v-if="isSize">Размер</p>
                        <p v-if="isColor">Цвет</p>
                        <p v-if="isOrientation">Ориентация</p>
                        <p>Кол-во</p>
                    </div>
                    <div class="color-item" v-for="offer in offerList" :key="offer.id">
                        <p class="color-item__name">{{offer.size}}</p>
                        <p class="color-item__name">{{offer.color}}</p>
                        <p class="color-item__quantity">{{offer.quantity}}</p>
                    </div>
                </div> -->
                <div class="order-options" v-for="offer in offerList" :key="offer.id">
                    <div class="order-options__item" v-if="isSize">
                        <p class="order-options__title">Размер:</p>
                        <p class="order-options__name">{{offer.size}}</p>
                    </div>
                    <div class="order-options__item" v-if="isOrientation">
                        <p class="order-options__title">Ориентация:</p>
                        <p class="order-options__name">{{offer.size}}</p>
                    </div>
                    <div class="order-options__item">
                        <p v-if="isColor" class="order-options__title">Цвет:</p>
                        <p class="order-options__name">{{offer.color}}</p>
                    </div>
                    <div class="order-options__item">
                        <p class="order-options__title">Количество:</p>
                        <p class="color-item__quantity">{{offer.quantity}}</p>
                    </div>
                </div>
                <!--<div class="order-item__rigging">
                    <div class="order-item__table-header">
                        <p>Осн-ка</p>
                        <p>Кол-во</p>
                    </div>
                    <div class="rigging-item">
                        <p class="rigging-item__name">A.P OM-5992-V</p>
                        <p class="rigging-item__quantity">1</p>
                    </div>
                    <div class="rigging-item">
                        <p class="rigging-item__name">A.P OM-5992-N</p>
                        <p class="rigging-item__quantity">1</p>
                    </div>
                </div>-->
            </div>
        </div>
        <div class="back" v-bind:style="{ backgroundImage: 'url('+ picture +')' }" v-on:click="showFullImg = false"></div>
    </div>
</template>
<script>
import addPreloader from '@/main'
export default {
    name: 'orderBasketItem',
    props: [
        "productId",
        "title",
        "number",
        "status"
    ],
    data: function(){
        return {
            id: 0,
            source: [],
            picture: "",
            productList: [],
            productInfo: {},
            offerList: [],
            isSize: false,
            isColor: false,
            isOrientation: false,
            showFullImg: false
        }
    },
    methods: {
        /**
         * удаление товара из корзины
         */
        onRemove(itemId){
            this.$store.dispatch('REMOVE_ITEM_BASKET', itemId);

            this.$bvToast.toast('Товар успешно удален из корзины!', {
                title: 'Оформление заказа',
                autoHideDelay: 3000,
                variant: 'warning',
                toaster: 'b-toaster-top-center',
                appendToast: false
            });

            this.$emit('remove', itemId);
        },
        /**
         * Картинка товара
         */
        setPicture(){
            // найти картинку из списка товаров коллекции
            let list = this.productList;

            for (let i = 0; i < Object.keys(list).length; i++) {
                let item = list[i];
                if(parseInt(item.id) === parseInt(this.id)){
                    this.picture = item.previewPicture?item.previewPicture:"";
                }
            }
        },
        getOffers(){
            let basketItems = this.$store.state.basketItems;
            let tmp = [];

            for(let i = 0; i < basketItems.length; i++){
                let item = basketItems[i];

                if(parseInt(this.id) === parseInt(item.productId)){
                    this.source.push(item);
                }
            }
            
        },
        geSkuPropertyMap(){
            let self = this
            for(let i = 0; i < this.source.length; i++){
                let item = this.source[i];

                if(typeof this.productInfo != "undefined"){
                    $.each(this.productInfo.offers, function(offerId, offer){
                        if(parseInt(offer.id) === parseInt(item.offerId)){
                            if(offer.prop.color.title){
                                self.isColor = true;
                            }
                            if(offer.prop.size.title){
                                self.isSize = true;
                            }
                            if(offer.prop.orientation.title){
                                self.isOrientation = true;
                            }
                            self.offerList.push({
                                id: offer.id,
                                size: offer.prop.size.title,
                                color: offer.prop.color.title,
                                quantity: 200
                            });
                        }
                    });
                    
                }
            }
            
        },

        getProductInfo(){
            for(let i = 0; i < this.productList.length; i++){
                let item = this.productList[i];

                if(parseInt(this.id) === parseInt(item.id)){
                    this.productInfo = item;
                }
            }
        }
    },
    watch: {
        status: function(newValue, oldValue){
            this.productList = this.$store.state.products;

            this.getProductInfo();
            this.geSkuPropertyMap();

            this.setPicture();
        }
    },
    computed: {
        countOffers(){
            return Object.keys(this.offerList).length;
        }
    },
    created() {
        this.id = this.$props.productId;
        
        this.getOffers();
        this.getProductInfo();
        this.geSkuPropertyMap();
    },
    mounted(){
        this.productList = this.$store.state.products;

        if(Object.keys(this.$store.state.products).length > 0){
            this.setPicture();
        }
    }
}
</script>
<style lang="scss" scoped>
    
    .order-options{
        width: 99%;
        display: flex;
        flex-direction: column;
        justify-content: flex-start;
        margin-bottom: 5px;
        padding-left: 5px;
        box-shadow: 1px 1px 3px rgba(0, 0, 0, 0.15);
        .order-options__item{
            width: 100%;
            display: flex;
            padding: 5px;
            .order-options__title{
                font-size: 12px;
                line-height: 16px;
                font-weight: 600;
                min-width: 50px;
            }
            .color-item__quantity{
                margin-left: auto;
                font-size: 12px;
                line-height: 16px;
                font-weight: 600;
            }
            .order-options__name{
                font-size: 12px;
                line-height: 16px;
            }
        }
    }
    .front{
        width: 100%;
        position: relative;
        display: flex;
        align-items: flex-start;
        padding: 5px;
        transition: 1s;
        backface-visibility: hidden;
        box-shadow: 2px 2px 6px rgba(0, 0, 0, 0.15);
        min-height: 330px;
    }
    .back{
        position: absolute;
        width: 100%;
        height: 100%;
        transition: 1s;
        backface-visibility: hidden;
        background-size: contain;
        background-position: center;
        background-repeat: no-repeat;
        box-shadow: 2px 2px 6px rgba(0, 0, 0, 0.15);
        // border: 1px solid #000;
        transform: rotateY(180deg);
        top: 0;
        left: 0;
        img{
            width: 100%;
        }
    }
    .order-item{
        perspective: 1000px;
        width: 330px;
        height: 330px;
        box-shadow: none;
        .order-item__discription-block{
            overflow: auto;
            max-height: 310px;
        }
        .order-item__discription-block::-webkit-scrollbar {
            width: 0; }

        .order-item__discription-block::-webkit-scrollbar {
            width: 0; }

        .order-item__discription-block::-webkit-scrollbar {
            width: 0; }
    }
    .order-item.showImg .front {transform: rotateY(180deg);}
    .order-item.showImg .back {transform: rotateY(360deg);}
</style>