import Vue from 'vue'
import Vuex from 'vuex'
import settings from '../settings'
import Axios from 'axios'

Vue.use(Vuex);

export default new Vuex.Store({
  state: {
    status: '',
    userID: localStorage.getItem('userID') || 0,
    user: {
      userName: '',
      userLastName: '',
      userAvatar: '',
      city: '',
      userID: ''
    },
    clientID: localStorage.getItem('clientID') || 0, // текущий клиент с которым ведется работа
    client: { // доп.информация по текущему клиенту
      id: 0,
      name: '',
      place: ''
    },
    collections: [],
    products: [],
    productID: 0,
    productInfo: {},
    userClients: [],
    addedRating: false,
    basketItems: localStorage.getItem('basketItems')?JSON.parse(localStorage.getItem('basketItems')):[]
  },
  mutations: {
    AUTH_SUCCESS(state, userInfo){
      state.status = 'autorized';
      state.user.userName = userInfo.userName;
      state.user.userLastName = userInfo.userLastName;
      state.user.userAvatar = userInfo.userAvatar;
      state.user.city = userInfo.city;
      state.user.userID = userInfo.userID;
      state.userID = userInfo.userID;
    },
    AUTH_ERROR(state){
      state.status = ''
      state.userID = ''
      state.user.userName = '';
      state.user.userLastName = '';
      state.user.userAvatar = '';
      state.user.city = '';
      state.user.userID = '';
      localStorage.removeItem('userID');

      state.collections = [];
      state.productID = 0;
      state.productInfo = {};
      state.products = [];
      state.userClients = [];
      localStorage.removeItem('clientID');

      localStorage.removeItem('basketItems');
      localStorage.removeItem('productRating');
      
    },
    SET_PRODUCT(state, id){
      state.productID = id;

      let info = [];
      for (let i = 0; i < state.products.length; i++) {
        let item = state.products[i];
        if(item.id == id){
          info = item;
        }
      }
      state.productInfo = info;
    },
    RESET_PRODUCT(state){
      state.productID = 0;
      state.productInfo = [];
    },
    CLIENT_ADD(state, companyInfo){ // установка значений по текущему клиенту
      state.client.name = companyInfo.title;
      state.client.place = companyInfo.region;
      state.client.id = companyInfo.id;
    },
    CLIENT_RESET(state){ // сброс клиента, нужно будет когда переходим к новому клиенту
      state.clientID = '';
      state.client = {
        id: 0,
        name: '',
        place: ''
      };
      localStorage.removeItem('clientID');
    },
    COLLECTION_LIST(state, list){ // доступные коллекции
      state.collections = list;
    },
    PRODUCT_LIST(state, list){ // доступные товары одной коллекции
      state.products = list;

    },
    SET_USER_CLIENTS(state, clients){
      let info = []
      for(let i = 0; i < clients.data.data.length; i++){
        info.push(clients.data.data[i])
      }
      state.userClients = info
    },
    SET_CURRENT_CLIENT(state, data){
      state.client = data;
    },
    USER_CLIENTS_RESET(state){
      state.userClients = []
    },
    ADD_RATING_INFO(state){
      state.addedRating = true
    },
    REMOVE_RATING_INFO(state){
      state.addedRating = false
    },
    ADD_TO_BASKET(state, params){
      state.basketItems = params;
      localStorage.setItem('basketItems', JSON.stringify(params));
    },
    CLEAR_BASKET(state){
      state.basketItems = [];
      localStorage.removeItem('basketItems');
    }
  },
  actions: {
    LOGIN({commit}, user){
      
      return new Promise((resolve, reject) => {
        Axios({
            method: 'post',
            url: settings.apiUrl+'/auth/',
            headers: {
              'Access-Control-Allow-Origin': '*'
            },
            crossDomain: true,
            data: JSON.stringify(user)
        }).then(resp => {
          let userInfo ={
            userName: resp.data.data.name,
            userLastName: resp.data.data.lastName,
            userAvatar: resp.data.data.avatar,
            city: resp.data.data.city,
            userID: resp.data.data.id
          }
          localStorage.setItem('userID', resp.data.data.id);
          commit('AUTH_SUCCESS', userInfo)
          resolve(resp)
        })
        .catch(err => {
          commit('AUTH_ERROR')
          reject(err)
        })
      })
    },
    LOGOUT({commit}){
      commit('AUTH_ERROR')
    },
    GET_USER_INFO({commit}){
      let userID = localStorage.getItem('userID');
      return new Promise((resolve, reject) => {
        Axios({
          method: 'get',
            url: settings.apiUrl+'/user/',
            headers: {
              'X-BitrixUserId': userID
            }
        }).then(resp => {
          let userInfo ={
            userName: resp.data.data.name,
            userLastName: resp.data.data.lastName,
            userAvatar: resp.data.data.avatar,
            city: resp.data.data.city,
            userID: resp.data.data.id
          }
          commit('AUTH_SUCCESS', userInfo)
          resolve(resp)
        })
        .catch(err => {
          commit('AUTH_ERROR')
          reject(err)
        })
      });
    },

    CLIENT_RESET({commit}){
      commit('CLIENT_RESET')
    },

    CLIENT_ADD({commit}, company){
      
      return new Promise((resolve, reject) => {
        Axios({
            method: 'post',
            url: settings.apiUrl+'/company/0/',
            data: company
        }).then(response => {
          let companyData = response.data.data;
          localStorage.setItem('clientID', companyData.id);
          resolve(response)
        })
        .catch(err => {
          commit('CLIENT_RESET');
          reject(err)
        })
      })
    },

    CLIENT_INFO({commit}){
      let self = this;
      
      return new Promise((resolve, reject) => {
        Axios({
            method: 'get',
            url: settings.apiUrl+'/company/'+self.state.clientID+'/'
        }).then(response => {
          let companyData = response.data.data;

          commit('CLIENT_ADD', companyData);
          resolve(response)
        })
        .catch(err => {
          commit('CLIENT_RESET');
          reject(err)
        })
      })
    },
    GET_COLLECTION_LIST({commit}){
      let self = this;
      
      return new Promise((resolve, reject) => {
        Axios({
            method: 'get',
            url: settings.apiUrl+'/collections/'
        }).then(response => {
          let items = response.data.data;

          commit('COLLECTION_LIST', items);
          resolve(items);
        })
        .catch(err => {
          reject(err)
        })
      })
    },

    GET_PRODUCT_LIST({commit}, collectionId){
      let self = this;
      
      return new Promise((resolve, reject) => {
        Axios({
            method: 'get',
            url: settings.apiUrl+'/collection/'+collectionId+'/'
        }).then(response => {
          let info = response.data.data;

          commit('PRODUCT_LIST', info.products);
          resolve(info);
        })
        .catch(err => {
          reject(err)
        })
      })
    },

    RESET_PRODUCT({commit}){
      commit('RESET_PRODUCT')
    },

    SET_PRODUCT({commit}, id){
      commit('SET_PRODUCT', id);
    },
    GET_CLIENTS_LIST({commit, state}){
      return new Promise((resolve, reject) => {
        Axios({
            method: 'get',
            url: settings.apiUrl + '/companies/',
            headers: {
              'X-BitrixUserId': localStorage.getItem('userID')
            }
        }).then(resp => {
          commit('SET_USER_CLIENTS', resp);

          let clientId = state.clientID;
          let clientData = [];

          for(let i = 0; i < resp.data.data.length; i++){
            if(parseInt(resp.data.data[i].id) === parseInt(clientId)){
              clientData = resp.data.data[i];
            }
          }

          commit('SET_CURRENT_CLIENT', clientData);
          resolve(resp)
        })
        .catch(err => {
          
          reject(err)
        })
      })
    },
    RESET_CLIENTS_LIST({commit}){
      commit('USER_CLIENTS_RESET')
    },
    SET_RATING({commit}){
      commit('ADD_RATING_INFO')
    },
    UNSET_RATING({commit}){
      commit('REMOVE_RATING_INFO')
    },
    ADD_TO_BASKET({commit, state}, params){
      let oldItems = state.basketItems;

      // объединяем текущий с новым
      let newParams = oldItems.concat(params);
      
      let result = [];
      let tmp = [];
      // делаем проход по новому и собираем повторяющиеся позиции
      for(let i = 0; i < newParams.length; i++){
        let itemI = newParams[i];

        // проверяем актуальность, чтобы избежать дублей
        let isActial = true;
        for(let k = 0; k < tmp.length; k++){
          if(tmp[k] == itemI.productId+"_"+itemI.offerId){
            isActial = false;
          }
        }

        if(isActial){
          let sum = parseInt(itemI.quantity);
          for(let j = 0; j < newParams.length; j++){
            let itemJ = newParams[j];
            if(j != i){
              // собрать суммарное кол-во
              if((itemJ.offerId == itemI.offerId) && (itemJ.productId == itemI.productId)){
                sum = sum + parseInt(itemJ.quantity);
              }
            }
          }

          // формируем результирующий массив по товару
          result.push({
            'collectionId': itemI.collectionId,
            'productId': itemI.productId,
            'productName': itemI.productName,
            'offerId': itemI.offerId,
            'offerName': itemI.offerName,
            'colorTitle': itemI.colorTitle,
            'quantity': sum
          });
          tmp.push(itemI.productId+"_"+itemI.offerId);
        }
      }

      commit('ADD_TO_BASKET', result);
    },
    REMOVE_ITEM_BASKET({commit, state}, productId){
      let newParams = state.basketItems;
      let result = [];
      let tmp = [];
      // делаем проход по новому и собираем повторяющиеся позиции
      for(let i = 0; i < newParams.length; i++){
        let item = newParams[i];

        if(parseInt(item.productId) != parseInt(productId)){
          // формируем результирующий массив по товару
          result.push({
            'collectionId': item.collectionId,
            'productId': item.productId,
            'productName': item.productName,
            'offerId': item.offerId,
            'offerName': item.offerName,
            'colorTitle': item.colorTitle,
            'quantity': item.quantity
          });
        }

      }

      commit('ADD_TO_BASKET', result);
    },
    CLEAR_BASKET({commit}){
      commit('CLEAR_BASKET')
    },
    CREATE_ORDER({commit, state}){
      
      let collectionId = 0;
      let basketItems = state.basketItems;

      // определить к какой коллекции относиться заказ
      if(Object.keys(basketItems).length > 0){

        for(let i = 0; i < basketItems.length; i++){
            let item = basketItems[i];
            collectionId = item.collectionId;
        }
      }

      if(parseInt(collectionId) > 0){
        // дата презентации
        let now = new Date();
        let datePresentation = function(date){
          var dd = date.getDate();
            if (dd < 10) dd = '0' + dd;
          
            var mm = date.getMonth() + 1;
            if (mm < 10) mm = '0' + mm;
          
            return dd + '.' + mm + '.' + date.getFullYear();
        };

        let requestData = {
          "companyId": state.clientID,
          "collectionId": collectionId,
          "datePresentation": datePresentation(now),
          "baskets": state.basketItems || [],
          "rating": localStorage.removeItem('getItem') || []
        };
        localStorage.setItem('collectionIdForFeedback', collectionId);
        return new Promise((resolve, reject) => {
          Axios({
              method: 'post',
              url: settings.apiUrl+'/order/',
              data: requestData
          }).then(response => {
            let info = response.data.data;

            commit('CLEAR_BASKET');
            commit('RESET_PRODUCT');

            localStorage.removeItem('productRating');

            resolve(info);
          })
          .catch(err => {
            reject(err)
          })
        })
      }
      else{
        return new Promise((resolve, reject) => {
          reject("Не указан параметр collectionId");
        })
      }
    }
  },
  getters: {
    test(state){
      return state
    },
    GET_RATING_INFO(state){
      return state.addedRating
    }
  },
  modules: {
  }
})
