<template>
    <div class="user"
        
         :class="{showSubmenu: showUserMenu}">
        <img v-bind:src="getUserAvatar" alt="">
        <p class="user__name">
            {{getUserName}} {{getUserLastName}}
            <span>{{getUserCity}}</span>
        </p>
        <div class="user__submenu" >
            <a href="" v-on:click.prevent="orderCreate" class="user__link">
                <div class="submenu-img"></div>
                <p>Ваш заказ</p>
            </a>
            <a href="" v-on:click.prevent="changeClient" class="user__link">
                <div class="submenu-img"></div>
                <p>Сменить клиента</p>
            </a>
            <a href="" v-on:click.prevent="logOut" class="user__link">
                <div class="submenu-img"></div>
                <p>Выйти</p>
            </a>
        </div>
    </div>
</template>
<script>
export default {
    data: () => ({
        showUserMenu: false,
        userName: '',
        userLastName: '',
        city: '',
        userAvatar: ''
    }), 
    methods: {
        showSubMenu(){
            let name = document.querySelector(".user__name");
            let menu = document.querySelector(".user__submenu");
            setTimeout(() => {
                let opacity = 0.1;
                let menuHeight = 0;
                let fadeIn = setInterval(() => {
                    name.style.display = 'flex';
                    if(opacity < 1){
                        name.style.opacity = opacity;
                        opacity += 0.1;
                        
                    }else{
                        clearInterval(fadeIn);
                    }
                }, 10);
                let showMenu = setInterval(() => {
                    if(menuHeight < 175){
                        menu.style.height = menuHeight + 'px';
                        menuHeight += 15;
                    }else{
                        clearInterval(showMenu);
                    }
                }, 10);
            },300)
        },
        hideSubMenu(){
            let name = document.querySelector(".user__name");
            let menu = document.querySelector(".user__submenu");
            name.style.display = 'none';
            name.style.opacity = 0;
            menu.style.height = 0 + 'px';
        },
        logOut(){
            this.$store.dispatch('LOGOUT');
            this.$store.dispatch('CLIENT_RESET');
            this.$store.dispatch('RESET_CLIENTS_LIST');
            this.$router.push('/')
        },
        changeClient(){
            this.$store.dispatch('CLIENT_RESET');
            this.$router.push('/registration')
        },
        orderCreate(){
            this.$router.push('/order');
        }
    },
    computed:{
        getUserName: function(){
            this.userName = this.$store.state.user.userName
            return this.userName
        },
        getUserLastName: function(){
            this.userLastName = this.$store.state.user.userLastName
            return this.userLastName
        },
        getUserCity: function(){
           this.city = this.$store.state.user.city
            return this.city
        },
        getUserAvatar: function(){
            this.userAvatar = this.$store.state.user.userAvatar
            return this.userAvatar
        }
    }, 
    created(){
        let that = this;
        document.addEventListener('click', function (e) {
            let user = document.querySelector(".user");
            if(user !== null){
                let userMenu = document.querySelector(".user__submenu");
                if(e.target == user || e.target == user.children[0]){
                    that.showUserMenu = true;
                    that.showSubMenu();
                    
                }else if(e.target == userMenu || e.target == user.userMenu){
                    return
                }else{
                    that.showUserMenu = false;
                    that.hideSubMenu();
                }
            }
        });
    }
}
</script>
