import Vue from 'vue'
import VueRouter from 'vue-router'


Vue.use(VueRouter)


const routes = [
  {
    path: '/',
    name: 'Enter',
    component: () => import('../views/Enter.vue')
  },
  {
    path: '/registration',
    name: 'Registration',
    component: () => import('../views/Registration.vue')
  },
  {
    path: '/catalog/:id',
    name: 'catalog',
    meta: {header: 'Header', subHeader: 'SubHeader'}, //Показать header на странице
    component: () => import('../views/Catalog.vue'),
    props: true,
    beforeEnter: (to, from, next) => {
      if(localStorage.getItem('userID') == null){ //Если в localStorage нет поля UserID, переход на главную
        next({ path: '/' })  
      }else if(localStorage.getItem('clientID') == null ){ //Если в localStorage нет поля clientID, переход на страницу регистрации клиента
        next({ path: '/registration' })
      }else{
        next()
      }
    }
  },
  {
    path: '/collections',
    name: 'collections',
    meta: {header: 'Header', subHeader: 'SubHeader'},
    component: () => import('../views/Collections.vue'),
    beforeEnter: (to, from, next) => {
      if(localStorage.getItem('userID') == null){
        next({ path: '/' })
      }else if(localStorage.getItem('clientID') == null ){
        next({ path: '/registration' })
      }else{
        next()
      }
    }
  },
  {
    path: '/order',
    name: 'orderList',
    meta: {header: 'Header', subHeader: 'SubHeader'},
    component: () => import('../views/OrderList.vue'),
    beforeEnter: (to, from, next) => {
      if(localStorage.getItem('userID') == null){
        next({ path: '/' })
      }else if(localStorage.getItem('clientID') == null ){
        next({ path: '/registration' })
      }else{
        next()
      }
    }
  },
  {
    path: '/catalog/:collection/:element',
    name: 'productCard',
    meta: {header: 'Header'},
    component: () => import('../views/ProductCard.vue'),
    props: true,
    beforeEnter: (to, from, next) => {
      if(localStorage.getItem('userID') == null){
        next({ path: '/' })
      }else if(localStorage.getItem('clientID') == null ){
        next({ path: '/registration' })
      }else{
        next()
      }
    }
  },
  {
    path: '/manufacture/:presentation',
    name: 'manufacture',
    meta: {header: 'Header', subHeader: 'SubHeader'},
    component: () => import('../views/ManufactureCreate.vue'),
    beforeEnter: (to, from, next) => {
      if(localStorage.getItem('userID') == null){
        next({ path: '/' })
      }else if(localStorage.getItem('clientID') == null ){
        next({ path: '/registration' })
      }else{
        next()
      }
    }
  },
  {
    path: '/manufacture-list',
    name: 'manufactureList',
    meta: {header: 'Header', subHeader: 'SubHeader'},
    component: () => import('../views/ManufactureList.vue'),
    beforeEnter: (to, from, next) => {
      if(localStorage.getItem('userID') == null){
        next({ path: '/' })
      }else if(localStorage.getItem('clientID') == null ){
        next({ path: '/registration' })
      }else{
        next()
      }
    }
  },
  {
    path: '/comment',
    name: 'comment',
    component: () => import('../views/comment.vue'),
    beforeEnter: (to, from, next) => {
      if(localStorage.getItem('userID') == null){
        next({ path: '/' })
      }else if(localStorage.getItem('clientID') == null ){
        next({ path: '/registration' })
      }else{
        next()
      }
    }
  },
]

const router = new VueRouter({
  mode: 'history',
  base: process.env.BASE_URL,
  routes
})

export default router
