<template>
    <div class="client-block">
        <div class="client-block__title">
            <p
                :class="visible ? null : 'collapsed'"
                :aria-expanded="visible ? 'true' : 'false'"
                v-bind:aria-controls = "getID"
                @click="visible = !visible">{{clientInfo.title}}</p>

            <a href="#" @click.prevent="tabIndex--" v-bind:class="{active: (tabIndex == 0)}" class="client-info"></a>
            <a href="#" @click.prevent="tabIndex++" v-bind:class="{active: (tabIndex == 1)}" class="client-presentation"></a>
        </div>
        <b-collapse v-model="visible" class="client-block__discription tab-content" accordion="clientsAcordion" v-bind:id="getID">
            <b-tabs v-model="tabIndex">
                <b-tab class="client-info-block" v-bind:id="getInfoID">
                    <div class="wrapper">
                        <p class="client-block__header">контактные данные</p>
                        <p class="client-text_style client-mail">{{clientInfo.email}}</p>
                        <p class="client-text_style client-phone">{{clientInfo.phone}}</p>
                        <p class="client-text_style client-adress">{{clientInfo.address}}</p>
                        <p class="client-text_style client-saler">{{clientInfo.description}}</p>
                    </div>
                </b-tab>
                <b-tab class="client-presentation-block" v-bind:id="getPresentationID">
                    <div class="wrapper">
                        <p class="client-block__header">презентации</p>
                        <!-- <a href="" class="client-text_style visited">Весна-Лето Ж 2020-21 (Ч1)</a>
                        <a href="" class="client-text_style visited">Весна-Лето М 2020-21</a>
                        <a href="" class="client-text_style">Весна-Лето Д 2020-21</a>
                        <a href="" class="client-text_style">Весна-Лето Ж 2020-21 (Ч2)</a> -->
                        <a v-on:click.prevent="onClickPresentDetail($event, collection)" href=""
                            class="client-text_style" :class="{visited:collection.isManufacture}" 
                            v-for="collection in collectionsList" :key='collection.id'>{{collection.title}}</a>
                        <div v-if="(collectionsList.length == 0)" class="client-text_style">Презентации отсутствуют!</div>
                    </div>
                </b-tab>
            </b-tabs>

        </b-collapse>
    </div>
</template>
<script>
import settings from '../../../settings'
export default {
    data: () => ({
        id: '',
        infoID: '',
        presentationID: '',
        visible: false,
        tabIndex: 1,
        collectionsList: ''
    }),
    props: ["clientInfo"],
    methods: {
        onClickPresentDetail(e, item){
            if(!item.isManufacture){
                this.$toasted.show('Создать отстройку по презентации?', {
                    action : [
                        {
                            text : 'Нет',
                            onClick : (e, toastObject) => {
                                toastObject.goAway(0);
                            }
                        },
                        {
                            text : 'Да',
                            onClick: (e, toastObject) => {
                                toastObject.goAway(0);
                                this.$router.push('/manufacture/'+item.id).catch(err => {});
                            }
                        }
                    ]
                });
            }
            else{
                this.$bvToast.toast('Отстройка по данной коллекции уже создана!', {
                    title: 'Создание отстройки',
                    autoHideDelay: 500,
                    variant: 'success',
                    toaster: 'b-toaster-top-center',
                    appendToast: false
                });
            }

            e.stopPropagation();
        },
    },
    computed: {
        getID: function(){
            this.id = "client" + this.clientInfo.id
            return this.id
        },
        getInfoID: function(){
            this.infoID = "info-client" + this.clientInfo.id
            return this.infoID
        },
        getPresentationID: function(){
            this.presentationID = "presentation-client" + this.clientInfo.id
            return this.presentationID
        }
    },
    created(){
        let id = this.clientInfo.id;
        this.$axios({
            method: 'GET',
            url: settings.apiUrl + '/presentation/'+ id +'/company/',
        }).then(resp => {
            // console.log(resp.data)
          this.collectionsList = resp.data.data
        })
        .catch(err => {
          console.log(err)
        })
    }
}
</script>